import vex
from langgraph.checkpoint.sqlite import SqliteSaver

memory = SqliteSaver.from_conn_string(":memory:")
graph = PolicyRenewalGraph().compile(checkpointer=memory)

@vex.guard("policy-renewal", rules={"cycle_limit": 5, "rate_increase_limit": "new_premium < old_premium * 1.2"})
def verified_renewal(customer_id, current_policy):
    config = {"configurable": {"thread_id": customer_id}}
    for attempt in range(3):  # Vex auto-detects cycles
        result = graph.invoke(current_policy, config)
        if vex.verify(result, context=config):
            return result
    raise Exception("Compliance failure: excessive cycles or rate hike")
